import{_ as t,o,c as n,ae as r}from"./chunks/framework.DTQlDYOH.js";const d=JSON.parse('{"title":"Reference: Move types","description":"","frontmatter":{},"headers":[],"relativePath":"reference/moves.md","filePath":"reference/moves.md"}'),a={name:"reference/moves.md"};function s(i,e,l,c,g,h){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="reference-move-types" tabindex="-1">Reference: Move types <a class="header-anchor" href="#reference-move-types" aria-label="Permalink to &quot;Reference: Move types&quot;">​</a></h1><p>Moves are defined under <strong>moves</strong> (or under <strong>turn.stages.&lt;stage&gt;.moves</strong>). Each move has a <strong>type</strong> and <strong>arguments</strong>; many support <strong>then</strong> for automatic follow-up moves.</p><h2 id="placenew" tabindex="-1">PlaceNew <a class="header-anchor" href="#placenew" aria-label="Permalink to &quot;PlaceNew&quot;">​</a></h2><p>Puts an entity from the bank into a destination (space or container).</p><ul><li><strong>entity</strong> — Matcher/conditions for which entity to place (e.g. current player’s marker). Supports <code>matchMultiple</code> and <code>count</code> to place several.</li><li><strong>arguments.destination</strong> — Where to place (conditions or matcher). Use <strong>playerChoice: true</strong> to let the player pick among valid destinations.</li><li><strong>arguments.position</strong> — Optional. Position in the destination (e.g. start/end of list).</li></ul><p>Used in: tic-tac-toe (place marker), Connect Four (drop piece), Reversi (place disc), Eights (play card).</p><h2 id="moveentity" tabindex="-1">MoveEntity <a class="header-anchor" href="#moveentity" aria-label="Permalink to &quot;MoveEntity&quot;">​</a></h2><p>Moves an existing entity to a new destination.</p><ul><li><strong>arguments.entity</strong> — Which entity to move (conditions; often <strong>playerChoice: true</strong>).</li><li><strong>arguments.destination</strong> — Where it can move (conditions; often <strong>playerChoice: true</strong>).</li></ul><p>Used in: Checkers (move/jump), Reversi (flip by moving/capturing).</p><h2 id="removeentity" tabindex="-1">RemoveEntity <a class="header-anchor" href="#removeentity" aria-label="Permalink to &quot;RemoveEntity&quot;">​</a></h2><p>Removes an entity from the game (e.g. capture).</p><ul><li><strong>arguments.entity</strong> — Which entity to remove (conditions or contextPath). Often used inside <strong>then</strong> after a move (e.g. remove the jumped piece).</li></ul><h2 id="takefrom" tabindex="-1">TakeFrom <a class="header-anchor" href="#takefrom" aria-label="Permalink to &quot;TakeFrom&quot;">​</a></h2><p>Takes an entity from a container (e.g. draw from deck).</p><ul><li><strong>arguments</strong> — Define the source and, if needed, how many. Used in card games (draw from stock).</li></ul><h2 id="setstate" tabindex="-1">SetState <a class="header-anchor" href="#setstate" aria-label="Permalink to &quot;SetState&quot;">​</a></h2><p>Updates an entity’s state (e.g. promote to king).</p><ul><li><strong>arguments.entity</strong> — The entity (often via <strong>contextPath</strong> or <strong>ForEach</strong> target).</li><li><strong>arguments.state</strong> — Object with <strong>property</strong> and <strong>value</strong> (e.g. property <code>&quot;isKing&quot;</code>, value <code>true</code>).</li></ul><p>Used in: Checkers (king pieces that reach the back row).</p><h2 id="setactiveplayers" tabindex="-1">SetActivePlayers <a class="header-anchor" href="#setactiveplayers" aria-label="Permalink to &quot;SetActivePlayers&quot;">​</a></h2><p>Changes whose turn it is or which stage they’re in.</p><ul><li><strong>options</strong> — e.g. set <strong>currentPlayer</strong> to stage <code>&quot;kingPieces&quot;</code> or <code>&quot;moveIfNoJump&quot;</code>.</li><li><strong>conditions</strong> — Optional. When to apply (e.g. <strong>NoPossibleMoves</strong> to advance stage only when no move is available).</li></ul><p>Used in: Checkers (jumpIfPossible → moveIfNoJump → kingPieces).</p><h2 id="endturn-passturn" tabindex="-1">EndTurn / PassTurn <a class="header-anchor" href="#endturn-passturn" aria-label="Permalink to &quot;EndTurn / PassTurn&quot;">​</a></h2><ul><li><strong>EndTurn</strong> — Ends the current turn (e.g. after a normal move).</li><li><strong>PassTurn</strong> — Pass without making a move; often has a <strong>conditions</strong> array with one object: <code>conditionType: &quot;NoPossibleMoves&quot;</code>, so it only runs when there are no legal moves.</li></ul><p>Both can appear in <strong>initialMoves</strong> of a turn or stage.</p><h2 id="foreach" tabindex="-1">ForEach <a class="header-anchor" href="#foreach" aria-label="Permalink to &quot;ForEach&quot;">​</a></h2><p>Runs a move once per target in a set.</p><ul><li><strong>arguments.targets</strong> — Condition or resolution that yields multiple targets (e.g. <strong>contextPath</strong> to a list, or <strong>map</strong> over spaces).</li><li><strong>move</strong> — The move rule to run (e.g. <strong>SetState</strong>, <strong>RemoveEntity</strong>). The <strong>loopTarget</strong> is available in context for each iteration.</li></ul><p>Used in: Checkers (king all pieces that reached the back row), Eights (deal cards to hands).</p><h2 id="pass-shuffle" tabindex="-1">Pass / Shuffle <a class="header-anchor" href="#pass-shuffle" aria-label="Permalink to &quot;Pass / Shuffle&quot;">​</a></h2><ul><li><strong>Pass</strong> — No-op (e.g. placeholder in a stage).</li><li><strong>Shuffle</strong> — Shuffles a container (e.g. deck). Used in card games.</li></ul><hr><p><strong>then</strong> — Any move can have a <strong>then</strong> array of move rules. After the main move runs successfully, the engine runs these in order (with shared context, e.g. <strong>moveArguments</strong>, <strong>originalTarget</strong>). Used for captures (RemoveEntity after MoveEntity) or advancing stages (SetActivePlayers).</p>',35)])])}const p=t(a,[["render",s]]);export{d as __pageData,p as default};
